"""Templates HTML embutidos (gerados de app/templates/*.html).

NÃO edite à mão — rode scripts/build_assets.py após mudar os .html.
Embutidos para o bundle serverless da Vercel (sem includeFiles).
"""

TEMPLATES = {
    'base.html': '<!doctype html>\n<html lang="pt-br">\n<head>\n  <meta charset="utf-8">\n  <meta name="viewport" content="width=device-width, initial-scale=1">\n  <title>{% block title %}Bolão da Copa 2026{% endblock %}</title>\n  <script src="https://cdn.tailwindcss.com"></script>\n  <script>\n    tailwind.config = {\n      theme: { extend: {\n        colors: { brand: { green: \'#0a8754\', yellow: \'#f4c430\', blue: \'#1d3f8a\' } },\n        fontFamily: { sans: [\'Inter\', \'ui-sans-serif\', \'system-ui\', \'sans-serif\'] },\n      } }\n    }\n  </script>\n  <link rel="preconnect" href="https://fonts.googleapis.com">\n  <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>\n  <link href="https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&display=swap" rel="stylesheet">\n  <style>body{font-family:\'Inter\',ui-sans-serif,system-ui,sans-serif}</style>\n</head>\n<body class="min-h-screen bg-slate-50 text-slate-800 antialiased flex flex-col">\n  <header class="sticky top-0 z-20 bg-white/90 backdrop-blur border-b border-slate-200">\n    <div class="max-w-4xl mx-auto px-4 h-16 flex items-center justify-between gap-4">\n      <a href="/" class="flex items-center gap-2.5 font-semibold text-slate-900">\n        <span class="inline-flex h-8 w-8 items-center justify-center rounded-lg bg-brand-green/10 text-lg">⚽</span>\n        <span class="tracking-tight">Bolão da Copa<span class="text-brand-green"> 2026</span></span>\n      </a>\n      <nav class="hidden sm:flex items-center gap-1 text-sm text-slate-500">\n        {% set nav = [(\'/\', \'Jogos\'), (\'/apostas\', \'Palpites\'), (\'/ranking\', \'Ranking\'), (\'/regras\', \'Regras\')] %}\n        {% for href, label in nav %}\n        <a href="{{ href }}" class="px-3 py-2 rounded-md hover:text-slate-900 hover:bg-slate-100 transition">{{ label }}</a>\n        {% endfor %}\n        {% if user and user.is_admin %}\n        <a href="/admin" class="px-3 py-2 rounded-md text-brand-blue hover:bg-slate-100 transition">Admin</a>\n        {% endif %}\n      </nav>\n      <div class="flex items-center gap-2">\n        {% if user %}\n          {% if user.picture_url %}\n          <img src="{{ user.picture_url }}" alt="" class="w-8 h-8 rounded-full ring-1 ring-slate-200" referrerpolicy="no-referrer">\n          {% endif %}\n          <span class="hidden md:inline text-sm text-slate-600">{{ user.name or user.email }}</span>\n          <a href="/auth/logout" class="text-xs px-2.5 py-1.5 rounded-md text-slate-500 hover:bg-slate-100">Sair</a>\n        {% else %}\n          <a href="/auth/login" class="text-sm px-3.5 py-2 rounded-lg bg-brand-green text-white font-medium hover:brightness-110 transition">Entrar</a>\n          {% if dev_login %}\n          <a href="/auth/dev-login" class="text-xs px-2 py-2 rounded-md text-slate-400 hover:bg-slate-100">dev</a>\n          {% endif %}\n        {% endif %}\n      </div>\n    </div>\n    <!-- detalhe sutil da bandeira -->\n    <div class="h-0.5 flex">\n      <div class="flex-1 bg-brand-green"></div>\n      <div class="flex-1 bg-brand-yellow"></div>\n      <div class="flex-1 bg-brand-blue"></div>\n    </div>\n    <nav class="sm:hidden flex items-center justify-around bg-white text-sm text-slate-500 border-b border-slate-100">\n      <a href="/" class="px-3 py-2.5">Jogos</a>\n      <a href="/apostas" class="px-3 py-2.5">Palpites</a>\n      <a href="/ranking" class="px-3 py-2.5">Ranking</a>\n      <a href="/regras" class="px-3 py-2.5">Regras</a>\n      {% if user and user.is_admin %}<a href="/admin" class="px-3 py-2.5 text-brand-blue">Admin</a>{% endif %}\n    </nav>\n  </header>\n\n  <main class="w-full max-w-4xl mx-auto px-4 py-8 flex-1">\n    {% if not user %}\n    <div class="mb-6 rounded-xl bg-white border border-slate-200 px-4 py-3 text-sm text-slate-600 flex items-center gap-2">\n      <span class="text-base">👋</span>\n      <span><a href="/auth/login" class="font-medium text-brand-green hover:underline">Entre com o Google</a> para registrar seus palpites.</span>\n    </div>\n    {% endif %}\n    {% block content %}{% endblock %}\n  </main>\n\n  <footer class="max-w-4xl mx-auto w-full px-4 py-8 text-center text-xs text-slate-400">\n    Bolão entre amigos · Copa do Mundo 2026 ·\n    <a href="https://github.com/marinabpassos/projeto_bolao" target="_blank" rel="noopener"\n       class="inline-flex items-center gap-1 hover:text-slate-600 transition">\n      <svg class="w-3.5 h-3.5" fill="currentColor" viewBox="0 0 24 24" aria-hidden="true">\n        <path d="M12 2C6.477 2 2 6.484 2 12.017c0 4.425 2.865 8.18 6.839 9.504.5.092.682-.217.682-.483 0-.237-.008-.868-.013-1.703-2.782.605-3.369-1.343-3.369-1.343-.454-1.158-1.11-1.466-1.11-1.466-.908-.62.069-.608.069-.608 1.003.07 1.531 1.032 1.531 1.032.892 1.53 2.341 1.088 2.91.832.092-.647.35-1.088.636-1.338-2.22-.253-4.555-1.113-4.555-4.951 0-1.093.39-1.988 1.029-2.688-.103-.253-.446-1.272.098-2.65 0 0 .84-.27 2.75 1.026A9.564 9.564 0 0112 6.844c.85.004 1.705.115 2.504.337 1.909-1.296 2.747-1.027 2.747-1.027.546 1.379.202 2.398.1 2.651.64.7 1.028 1.595 1.028 2.688 0 3.848-2.339 4.695-4.566 4.943.359.309.678.92.678 1.855 0 1.338-.012 2.419-.012 2.747 0 .268.18.58.688.482A10.019 10.019 0 0022 12.017C22 6.484 17.522 2 12 2z"/>\n      </svg>\n      Sugerir melhoria\n    </a>\n  </footer>\n</body>\n</html>\n',
    'jogos.html': '{% extends "base.html" %}\n{% import "_match_card.html" as cards %}\n{% block title %}Jogos · Bolão da Copa 2026{% endblock %}\n{% block content %}\n<h1 class="text-xl font-semibold text-slate-900 tracking-tight">Jogos</h1>\n<p class="text-sm text-slate-500 mb-6">A partir da 3ª rodada da fase de grupos · editável até o apito.</p>\n\n{% if not groups %}\n  <div class="rounded-xl bg-white border border-slate-200 p-8 text-center text-slate-400">\n    Os jogos ainda não foram cadastrados.\n  </div>\n{% endif %}\n\n{% if view.view_mode == \'bracket\' %}\n  {% include "_bracket.html" %}\n{% else %}\n  {% for stage, matches in groups %}\n  <section class="mb-7">\n    <h2 class="text-xs font-semibold uppercase tracking-wider text-slate-400 mb-2.5">{{ stage_labels[stage] }}</h2>\n    <div class="grid gap-2.5">\n      {% for m in matches %}\n      {{ cards.match_card(m, my_preds.get(m.id), my_br.get(m.id), user, is_open[m.id], saved) }}\n      {% endfor %}\n    </div>\n  </section>\n  {% endfor %}\n{% endif %}\n{% endblock %}\n',
    '_match_card.html': '{% macro team_flag(name, cls) -%}\n  {%- set url = flag_url(name) -%}\n  {%- if url -%}\n    <img src="{{ url }}" alt="" loading="lazy" class="inline-block w-5 h-auto rounded-[2px] shadow-sm align-[-2px] {{ cls }}">\n  {%- else -%}\n    <span class="inline-block w-5 h-3.5 rounded-[2px] bg-slate-200 align-[-2px] {{ cls }}"></span>\n  {%- endif -%}\n{%- endmacro %}\n\n{% macro match_card(m, pred, br, user, open, saved) %}\n<article id="jogo-{{ m.id }}" class="bg-white rounded-xl border border-slate-200 p-4 hover:border-slate-300 transition">\n  {% if saved == m.id|string or saved == \'brasil-\' ~ m.id|string %}\n  <div class="mb-2.5 rounded-md bg-brand-green/10 border border-brand-green/30 px-3 py-1.5 text-sm text-brand-green font-medium text-center">✓ Palpite salvo!</div>\n  {% endif %}\n  <div class="flex items-center justify-between text-xs mb-2.5">\n    <span class="text-slate-400">{{ m.kickoff_at | dt_br }}</span>\n    {% if m.finished %}<span class="font-medium text-brand-green">Encerrado</span>\n    {% elif open %}<span class="inline-flex items-center gap-1 font-medium text-slate-500"><span class="h-1.5 w-1.5 rounded-full bg-brand-green"></span>Aberto</span>\n    {% else %}<span class="text-slate-300">Fechado</span>{% endif %}\n  </div>\n\n  {% if not m.teams_decided %}\n    <div class="text-center text-sm text-slate-400 py-2">⏳ Aguardando definição dos times</div>\n  {% else %}\n    <div class="flex items-center justify-center gap-3 text-base font-medium text-slate-800 mb-1">\n      <span class="flex-1 text-right">{% if m.is_brazil %}<span class="text-brand-yellow">★</span> {% endif %}{{ m.home_team }} {{ team_flag(m.home_team, \'ml-1\') }}</span>\n      {% if m.finished %}\n        <span class="px-2.5 py-1 rounded-md bg-slate-900 text-white text-sm tabular-nums">{{ m.home_score }} : {{ m.away_score }}</span>\n        {% if m.who_advanced %}\n        <span class="text-xs text-slate-400">→ {{ m.home_team if m.who_advanced == \'home\' else m.away_team }}</span>\n        {% endif %}\n      {% else %}\n        <span class="text-slate-300 text-sm">vs</span>\n      {% endif %}\n      <span class="flex-1 text-left">{{ team_flag(m.away_team, \'mr-1\') }} {{ m.away_team }}{% if m.is_brazil %} <span class="text-brand-yellow">★</span>{% endif %}</span>\n    </div>\n\n    {% if user and open %}\n      {% if pred %}\n      <p class="text-center text-xs text-brand-green mt-2 mb-0.5">✓ Palpite salvo: <b>{{ pred.home_pred }} : {{ pred.away_pred }}</b>{% if m.stage != \'grupos\' and pred and pred.qualifier_pred %} · {{ \'leva o 3º\' if m.stage == \'terceiro\' else \'avança\' }}: <b>{{ m.home_team if pred.qualifier_pred == \'home\' else m.away_team }}</b>{% endif %} — editável até o apito</p>\n      {% endif %}\n      <form method="post" action="/palpite/{{ m.id }}" class="flex flex-wrap items-center justify-center gap-2 mt-2">\n        <div class="flex items-center justify-center gap-2 w-full">\n          <input type="number" name="home_pred" min="0" value="{{ pred.home_pred if pred else \'\' }}"\n                 class="w-14 text-center border border-slate-300 rounded-md py-1.5 focus:border-brand-green focus:ring-1 focus:ring-brand-green outline-none" required>\n          <span class="text-slate-300">:</span>\n          <input type="number" name="away_pred" min="0" value="{{ pred.away_pred if pred else \'\' }}"\n                 class="w-14 text-center border border-slate-300 rounded-md py-1.5 focus:border-brand-green focus:ring-1 focus:ring-brand-green outline-none" required>\n          <button class="ml-2 px-3.5 py-1.5 rounded-md bg-brand-green text-white text-sm font-medium hover:brightness-110 transition">{% if pred %}Atualizar{% else %}Salvar{% endif %}</button>\n        </div>\n        {% if m.stage != \'grupos\' %}\n        {% set already_tied = pred and pred.home_pred == pred.away_pred and pred.qualifier_pred %}\n        <div id="qualifier-{{ m.id }}"\n             class="w-full mt-2"\n             style="{{ \'\' if already_tied else \'display:none\' }}">\n          <p class="text-xs text-slate-400 mb-1.5 text-center">Em caso de empate, {{ \'quem fica com o 3º lugar?\' if m.stage == \'terceiro\' else \'quem avança?\' }} <span class="font-medium text-brand-green">+5 pts</span></p>\n          <div class="flex justify-center gap-6 text-sm">\n            <label class="flex items-center gap-1.5 cursor-pointer">\n              <input type="radio" name="qualifier_pred" value="home"\n                     {{ \'checked\' if pred and pred.qualifier_pred == \'home\' }}\n                     {{ \'required\' if already_tied }}>\n              <span class="text-slate-700">{{ m.home_team }}</span>\n            </label>\n            <label class="flex items-center gap-1.5 cursor-pointer">\n              <input type="radio" name="qualifier_pred" value="away"\n                     {{ \'checked\' if pred and pred.qualifier_pred == \'away\' }}\n                     {{ \'required\' if already_tied }}>\n              <span class="text-slate-700">{{ m.away_team }}</span>\n            </label>\n          </div>\n        </div>\n        <script>\n        (function() {\n          var form   = document.currentScript.closest(\'form\');\n          var div    = document.getElementById(\'qualifier-{{ m.id }}\');\n          var homeIn = form.querySelector(\'[name="home_pred"]\');\n          var awayIn = form.querySelector(\'[name="away_pred"]\');\n          var radios = div.querySelectorAll(\'input[type="radio"]\');\n\n          function update() {\n            var h = homeIn.value.trim();\n            var a = awayIn.value.trim();\n            var isTie = h !== \'\' && a !== \'\' && h === a;\n            div.style.display = isTie ? \'\' : \'none\';\n            radios.forEach(function(r) {\n              r.disabled = !isTie;\n              r.required = isTie;\n              if (!isTie) r.checked = false;\n            });\n          }\n\n          homeIn.addEventListener(\'input\', update);\n          awayIn.addEventListener(\'input\', update);\n          update();\n        })();\n        </script>\n        {% endif %}\n      </form>\n    {% elif pred %}\n      <p class="text-center text-sm text-slate-500 mt-2">\n        Seu palpite: <b class="text-slate-700">{{ pred.home_pred }} : {{ pred.away_pred }}</b>{% if m.stage != \'grupos\' and pred.qualifier_pred %} · {{ \'leva o 3º\' if m.stage == \'terceiro\' else \'avança\' }}: <b class="text-slate-700">{{ m.home_team if pred.qualifier_pred == \'home\' else m.away_team }}</b>{% endif %}\n        {% if m.finished %}· <span class="font-semibold text-brand-green">{{ pred.points }} pts</span>{% endif %}\n      </p>\n    {% elif not user %}\n      <p class="text-center text-xs text-slate-400 mt-2">Entre para palpitar.</p>\n    {% else %}\n      <p class="text-center text-xs text-slate-400 mt-2">Você não palpitou neste jogo.</p>\n    {% endif %}\n\n    {% if m.is_brazil %}\n    <div class="mt-3 pt-3 border-t border-dashed border-slate-200">\n      <p class="text-xs font-medium text-slate-500 mb-2 text-center">Palpites do jogo do Brasil · 3 pts cada</p>\n      {% if user and open %}\n      {% if br %}\n      <p class="text-center text-xs text-brand-green mb-1">✓ Salvo: Neymar <b>{{ \'Sim\' if br.neymar_in else \'Não\' }}</b> · Endrick <b>{{ \'Sim\' if br.endrick_in else \'Não\' }}</b> — editável até o apito</p>\n      {% endif %}\n      <form method="post" action="/apostas/brasil-jogo/{{ m.id }}" class="flex flex-wrap items-center justify-center gap-3 text-sm">\n        <label class="flex items-center gap-1.5 text-slate-600">Neymar entra?\n          <select name="neymar_in" class="border border-slate-300 rounded-md py-1.5 px-2 outline-none focus:border-brand-green">\n            <option value="sim" {{ \'selected\' if br and br.neymar_in }}>Sim</option>\n            <option value="nao" {{ \'selected\' if br and not br.neymar_in }}>Não</option>\n          </select>\n        </label>\n        <label class="flex items-center gap-1.5 text-slate-600">Endrick entra?\n          <select name="endrick_in" class="border border-slate-300 rounded-md py-1.5 px-2 outline-none focus:border-brand-green">\n            <option value="sim" {{ \'selected\' if br and br.endrick_in }}>Sim</option>\n            <option value="nao" {{ \'selected\' if br and not br.endrick_in }}>Não</option>\n          </select>\n        </label>\n        <button class="px-3.5 py-1.5 rounded-md bg-brand-blue text-white text-sm font-medium hover:brightness-110 transition">{% if br %}Atualizar{% else %}Salvar{% endif %}</button>\n      </form>\n      {% elif br %}\n      <p class="text-center text-sm text-slate-500">\n        Neymar: <b>{{ \'Sim\' if br.neymar_in else \'Não\' }}</b> ·\n        Endrick: <b>{{ \'Sim\' if br.endrick_in else \'Não\' }}</b>\n        {% if m.finished %}· <span class="font-semibold text-brand-green">{{ br.points }} pts</span>{% endif %}\n      </p>\n      {% endif %}\n      {% if m.finished and m.neymar_played is not none %}\n      <p class="text-center text-xs text-slate-400 mt-1">\n        Real — Neymar: {{ \'entrou\' if m.neymar_played else \'não entrou\' }} ·\n        Endrick: {{ \'entrou\' if m.endrick_played else \'não entrou\' }}\n      </p>\n      {% endif %}\n    </div>\n    {% endif %}\n  {% endif %}\n</article>\n{% endmacro %}\n',
    '_bracket.html': '{% import "_match_card.html" as cards %}\n\n{# ---------- mini-chave: torneio inteiro, lado A <- 🏆 -> lado B ---------- #}\n{% macro mini_pair(m, live) %}\n<a href="/?fase={{ m.stage if m else \'\' }}" class="flex flex-col gap-px p-0.5 rounded border {{ \'border-brand-green bg-brand-green/10\' if live else \'border-slate-200 bg-slate-50\' }}">\n  {% for name in ([m.home_team, m.away_team] if m and m.teams_decided else [None, None]) %}\n    {% set url = name and flag_url(name, 20) %}\n    {% if url %}<img src="{{ url }}" alt="{{ name }}" loading="lazy" class="w-[13px] h-[10px] object-cover rounded-[1px]">\n    {% else %}<span class="w-[13px] h-[10px] bg-slate-200 rounded-[1px]"></span>{% endif %}\n  {% endfor %}\n</a>\n{% endmacro %}\n\n<div class="bg-white rounded-xl border border-slate-200 p-2.5 mb-3">\n  <p class="text-[8px] font-semibold uppercase tracking-wider text-slate-400 text-center mb-1.5">Chave completa · toque numa fase para navegar</p>\n  <div class="flex items-center justify-between gap-1">\n    {% for stage in [\'oitavas\', \'quartas\', \'semi\'] %}\n    <div class="flex flex-col gap-1 items-center flex-1">\n      {% for pos in range(1, (view.bracket[stage]|length) + 1) if pos <= (view.bracket[stage]|length) // 2 %}\n        {{ mini_pair(view.bracket[stage][pos], stage == view.selected_stage) }}\n      {% endfor %}\n      <span class="text-[7px] text-slate-400">{{ stage[:3]|upper }}·A</span>\n    </div>\n    {% endfor %}\n    <a href="/?fase=final" class="flex flex-col items-center flex-1">\n      <span class="text-sm">🏆</span><span class="text-[7px] text-slate-400">FINAL</span>\n    </a>\n    {% for stage in [\'semi\', \'quartas\', \'oitavas\'] %}\n    <div class="flex flex-col gap-1 items-center flex-1">\n      {% for pos in range(1, (view.bracket[stage]|length) + 1) if pos > (view.bracket[stage]|length) // 2 %}\n        {{ mini_pair(view.bracket[stage][pos], stage == view.selected_stage) }}\n      {% endfor %}\n      <span class="text-[7px] text-slate-400">{{ stage[:3]|upper }}·B</span>\n    </div>\n    {% endfor %}\n  </div>\n</div>\n\n{# ---------- fases anteriores recolhidas ---------- #}\n{% if view.past_stages %}\n<div class="mb-3">\n  <button type="button" onclick="var el=document.getElementById(\'fases-passadas\'); el.classList.toggle(\'hidden\'); this.querySelector(\'span+span\').textContent = el.classList.contains(\'hidden\') ? \'ver ▸\' : \'esconder ▾\'"\n          class="w-full flex items-center justify-between bg-slate-100 border border-slate-200 rounded-lg px-3 py-1.5 text-xs text-slate-500">\n    <span class="truncate">Fases anteriores: <b class="text-slate-600">{% for s in view.past_stages %}{{ stage_labels[s] }}{{ \' · \' if not loop.last }}{% endfor %}</b></span>\n    <span class="text-brand-green font-semibold shrink-0 ml-2">ver ▸</span>\n  </button>\n  {# escondido via JS no load — sem JS o histórico fica visível (degradação) #}\n  <div id="fases-passadas" class="mt-3">\n    {% for stage, matches_da_fase in past_groups %}\n    <section class="mb-5">\n      <h2 class="text-xs font-semibold uppercase tracking-wider text-slate-400 mb-2.5">{{ stage_labels[stage] }}</h2>\n      <div class="grid gap-2.5">\n        {% for m in matches_da_fase %}\n        {{ cards.match_card(m, my_preds.get(m.id), my_br.get(m.id), user, is_open[m.id], saved) }}\n        {% endfor %}\n      </div>\n    </section>\n    {% endfor %}\n  </div>\n</div>\n{% endif %}\n\n{# ---------- abas Lado A | Lado B (sublinhado) ---------- #}\n{% if view.selected_stage != \'final\' %}\n<div class="flex justify-center gap-6 border-b border-slate-200 mb-4" id="abas-lado">\n  <button type="button" data-lado="a" onclick="trocaLado(\'a\')" class="aba-lado text-sm font-semibold text-slate-900 border-b-2 border-brand-green -mb-px pb-1.5 px-1">Lado A</button>\n  <button type="button" data-lado="b" onclick="trocaLado(\'b\')" class="aba-lado text-sm text-slate-400 border-b-2 border-transparent -mb-px pb-1.5 px-1">Lado B</button>\n</div>\n{% endif %}\n\n{# ---------- árvore vertical do lado selecionado ---------- #}\n{% macro linha_time(m, name) %}\n  {% set url = flag_url(name) %}\n  <div class="flex items-center gap-1.5 py-0.5 text-sm text-slate-800">\n    {% if url %}<img src="{{ url }}" alt="" loading="lazy" class="w-[18px] h-auto rounded-[2px] shadow-sm">\n    {% else %}<span class="w-[18px] h-[13px] bg-slate-200 rounded-[2px]"></span>{% endif %}\n    <span class="flex-1 truncate">{% if m.is_brazil and name == \'Brasil\' %}<span class="text-brand-yellow">★</span> {% endif %}{{ name }}</span>\n    {% if m.finished %}<span class="font-bold tabular-nums {{ \'text-slate-900\' if (name == m.home_team and m.who_advanced == \'home\') or (name == m.away_team and m.who_advanced == \'away\') else \'text-slate-400\' }}">{{ m.home_score if name == m.home_team else m.away_score }}</span>\n    {% else %}<span class="text-slate-300">–</span>{% endif %}\n  </div>\n{% endmacro %}\n\n{% macro arvore(pairs, lado) %}\n<div id="lado-{{ lado }}" class="lado-chave">\n  <h2 class="text-xs font-semibold uppercase tracking-wider text-slate-400 mb-2.5">{{ stage_labels[view.selected_stage] }}{{ \' · Lado \' ~ lado|upper if view.selected_stage != \'final\' }}</h2>\n  {% for pair in pairs %}\n  <div class="flex items-center mb-2.5">\n    <div class="flex-1 grid gap-2">\n      {% for pos, m in pair.games %}\n        {% if m and m.teams_decided %}\n        <div>\n          <button type="button" onclick="document.getElementById(\'card-{{ m.id }}\').classList.toggle(\'hidden\')"\n                  class="w-full text-left bg-white rounded-xl border {{ \'border-brand-green\' if is_open[m.id] else \'border-slate-200\' }} px-3 py-1.5 hover:border-slate-400 transition">\n            {{ linha_time(m, m.home_team) }}\n            {{ linha_time(m, m.away_team) }}\n            <p class="text-[10px] mt-0.5 {{ \'text-brand-green\' if my_preds.get(m.id) else \'text-slate-400\' }}">\n              {% if m.finished and m.who_advanced %}→ {{ m.home_team if m.who_advanced == \'home\' else m.away_team }} avançou\n              {% elif my_preds.get(m.id) %}✓ seu palpite: {{ my_preds[m.id].home_pred }}:{{ my_preds[m.id].away_pred }} · toque para editar\n              {% elif is_open[m.id] %}● aberto · toque para palpitar\n              {% else %}{{ m.kickoff_at | dt_br }}{% endif %}\n            </p>\n          </button>\n          <div id="card-{{ m.id }}" class="mt-2 card-palpite{{ \' card-salvo\' if saved == m.id|string or saved == \'brasil-\' ~ m.id|string }}">\n            {{ cards.match_card(m, my_preds.get(m.id), my_br.get(m.id), user, is_open[m.id], saved) }}\n          </div>\n        </div>\n        {% else %}\n        <div class="rounded-xl border border-dashed border-slate-300 bg-slate-100 px-3 py-3 text-center text-xs text-slate-400">⏳ A definir{% if m %} · {{ m.kickoff_at | dt_br }}{% endif %}</div>\n        {% endif %}\n      {% endfor %}\n    </div>\n    {% if pair.target %}\n    <div class="w-2.5 self-stretch my-4 border-y-2 border-r-2 border-slate-300 rounded-r-md shrink-0"></div>\n    <div class="w-16 shrink-0 ml-1 text-center text-[10px] text-slate-400">\n      <div class="rounded-lg border border-dashed border-slate-300 bg-slate-100 py-2">{{ pair.target }}</div>\n    </div>\n    {% endif %}\n  </div>\n  {% endfor %}\n</div>\n{% endmacro %}\n\n{% macro jogo_final(m, titulo, dourado) %}\n{% set box = \'bg-gradient-to-br from-amber-50 via-white to-amber-50/60 border-amber-300 hover:border-amber-400\' if dourado else \'bg-white border-slate-200 hover:border-slate-400\' %}\n{% if m and m.teams_decided %}\n<div class="mb-3">\n  <button type="button" onclick="document.getElementById(\'card-{{ m.id }}\').classList.toggle(\'hidden\')"\n          class="w-full text-left rounded-2xl border-2 {{ box }} px-4 {{ \'py-4\' if dourado else \'py-3\' }} shadow-sm transition">\n    <p class="text-[10px] font-semibold uppercase tracking-wider {{ \'text-amber-600\' if dourado else \'text-amber-800\' }} mb-2 text-center">{{ titulo }} · {{ m.kickoff_at | dt_br }}</p>\n    <div class="flex items-center justify-center gap-3 {{ \'text-lg\' if dourado else \'text-base\' }} font-semibold text-slate-900">\n      <span class="flex-1 text-right truncate">{% if m.is_brazil and m.home_team == \'Brasil\' %}<span class="text-brand-yellow">★</span> {% endif %}{{ m.home_team }}</span>\n      {% set url = flag_url(m.home_team) %}\n      {% if url %}<img src="{{ url }}" alt="" loading="lazy" class="{{ \'w-9\' if dourado else \'w-7\' }} h-auto rounded shadow">{% else %}<span class="{{ \'w-9 h-6\' if dourado else \'w-7 h-5\' }} bg-slate-200 rounded inline-block"></span>{% endif %}\n      {% if m.finished %}\n        <span class="px-2.5 py-1 rounded-md bg-slate-900 text-white text-sm tabular-nums">{{ m.home_score }} : {{ m.away_score }}</span>\n      {% else %}\n        <span class="text-slate-300 text-sm">vs</span>\n      {% endif %}\n      {% set url = flag_url(m.away_team) %}\n      {% if url %}<img src="{{ url }}" alt="" loading="lazy" class="{{ \'w-9\' if dourado else \'w-7\' }} h-auto rounded shadow">{% else %}<span class="{{ \'w-9 h-6\' if dourado else \'w-7 h-5\' }} bg-slate-200 rounded inline-block"></span>{% endif %}\n      <span class="flex-1 text-left truncate">{{ m.away_team }}{% if m.is_brazil and m.away_team == \'Brasil\' %} <span class="text-brand-yellow">★</span>{% endif %}</span>\n    </div>\n    <p class="text-[11px] mt-2 text-center {{ \'text-brand-green\' if my_preds.get(m.id) else \'text-slate-400\' }}">\n      {% if m.finished and m.who_advanced %}→ {{ m.home_team if m.who_advanced == \'home\' else m.away_team }} {{ \'ficou em 3º 🥉\' if m.stage == \'terceiro\' else \'é campeão! 🏆\' }}\n      {% elif my_preds.get(m.id) %}✓ seu palpite: {{ my_preds[m.id].home_pred }}:{{ my_preds[m.id].away_pred }} · toque para editar\n      {% elif is_open[m.id] %}● aberto · toque para palpitar\n      {% else %}fechado{% endif %}\n    </p>\n  </button>\n  <div id="card-{{ m.id }}" class="mt-2 card-palpite{{ \' card-salvo\' if saved == m.id|string or saved == \'brasil-\' ~ m.id|string }}">\n    {{ cards.match_card(m, my_preds.get(m.id), my_br.get(m.id), user, is_open[m.id], saved) }}\n  </div>\n</div>\n{% elif m %}\n<div class="mb-3 rounded-2xl border-2 border-dashed border-slate-300 bg-slate-100 px-4 py-4 text-center text-xs text-slate-400">\n  {{ titulo }} · ⏳ A definir · {{ m.kickoff_at | dt_br }}\n</div>\n{% endif %}\n{% endmacro %}\n\n{% macro degrau(pos, nome, cor, altura, texto=\'text-white\') %}\n<div class="flex flex-col items-center justify-end gap-1 w-16">\n  {% if nome %}\n    {% set url = flag_url(nome) %}\n    {% if url %}<img src="{{ url }}" alt="" loading="lazy" class="w-6 h-auto rounded-[2px] shadow-sm">{% endif %}\n    <span class="text-[10px] text-slate-600 font-medium truncate max-w-full">{{ nome }}</span>\n  {% else %}\n    <span class="text-slate-300 text-sm">?</span>\n  {% endif %}\n  <div class="w-full {{ altura }} {{ cor }} rounded-t-md text-center text-[10px] font-bold {{ texto }} pt-0.5">{{ pos }}º</div>\n</div>\n{% endmacro %}\n\n{% if view.selected_stage == \'final\' %}\n  {{ jogo_final(view.final_match, \'🏆 Grande final\', true) }}\n  {{ jogo_final(view.terceiro_match, \'🥉 Disputa de 3º lugar\', false) }}\n  {% if view.podium %}\n  <div class="bg-white rounded-xl border border-slate-200 p-4 mt-4">\n    <p class="text-[10px] font-semibold uppercase tracking-wider text-slate-400 text-center mb-3">Pódio da Copa 2026</p>\n    <div class="flex items-end justify-center gap-2">\n      {{ degrau(2, view.podium[2], \'bg-slate-400\', \'h-14\') }}\n      {{ degrau(1, view.podium[1], \'bg-amber-400\', \'h-20\') }}\n      {{ degrau(3, view.podium[3], \'bg-amber-700\', \'h-10\') }}\n      {{ degrau(4, view.podium[4], \'bg-slate-200\', \'h-6\', \'text-slate-500\') }}\n    </div>\n  </div>\n  {% endif %}\n{% else %}\n  {{ arvore(view.pairs_a, \'a\') }}\n  {% if view.pairs_b %}{{ arvore(view.pairs_b, \'b\') }}{% endif %}\n{% endif %}\n\n{# ---------- fases futuras compactas ---------- #}\n{% if view.future_rows %}\n<h2 class="text-xs font-semibold uppercase tracking-wider text-slate-400 mt-5 mb-2">Mais adiante</h2>\n<div class="grid gap-1.5">\n  {% for row in view.future_rows %}\n  <div class="bg-white rounded-lg border border-slate-200 px-3 py-2 text-xs text-slate-400 flex justify-between">\n    <span>{% if row.label == \'FINAL\' %}🏆 {% endif %}{{ row.label }} · A definir</span>\n    <span>{{ row.match.kickoff_at | dt_br if row.match }}</span>\n  </div>\n  {% endfor %}\n</div>\n{% endif %}\n\n<script>\n// Esconde via JS o que é interativo — sem JS, cards e histórico ficam visíveis (degradação).\n// O card recém-salvo (.card-salvo) fica aberto para o "✓ Palpite salvo!" aparecer.\ndocument.querySelectorAll(\'.card-palpite:not(.card-salvo)\').forEach(function (el) { el.classList.add(\'hidden\'); });\nvar fp = document.getElementById(\'fases-passadas\');\nif (fp) { fp.classList.add(\'hidden\'); }\n\nfunction trocaLado(lado) {\n  document.querySelectorAll(\'.lado-chave\').forEach(function (el) {\n    el.classList.toggle(\'hidden\', el.id !== \'lado-\' + lado);\n  });\n  document.querySelectorAll(\'.aba-lado\').forEach(function (btn) {\n    var on = btn.dataset.lado === lado;\n    btn.classList.toggle(\'text-slate-900\', on);\n    btn.classList.toggle(\'font-semibold\', on);\n    btn.classList.toggle(\'border-brand-green\', on);\n    btn.classList.toggle(\'text-slate-400\', !on);\n    btn.classList.toggle(\'border-transparent\', !on);\n  });\n}\nif (document.getElementById(\'abas-lado\')) { trocaLado(\'a\'); }\n</script>\n',
    'apostas.html': '{% extends "base.html" %}\n{% block title %}Palpites · Bolão da Copa 2026{% endblock %}\n{% block content %}\n<h1 class="text-xl font-semibold text-slate-900 tracking-tight mb-6">Palpites especiais</h1>\n\n{% if saved %}\n<div class="mb-4 rounded-lg bg-brand-green/10 border border-brand-green/30 px-4 py-2.5 text-sm text-brand-green font-medium">✓ Aposta salva com sucesso!</div>\n{% endif %}\n\n{% if not user %}\n  <div class="rounded-xl bg-white border border-slate-200 p-8 text-center text-slate-400">Entre com o Google para fazer seus palpites.</div>\n{% else %}\n<div class="grid md:grid-cols-2 gap-4">\n\n  <!-- Artilheiro -->\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-1">Artilheiro da Copa</h2>\n    <p class="text-sm text-slate-500 mb-3">\n      Vale mais quanto mais cedo você cravar — congela na fase do <b>último palpite</b>.\n      Faixa de agora: <b class="text-brand-green">{{ current_tier }} pts</b>.\n    </p>\n    {% if artilheiro %}\n    <p class="text-sm mb-3 rounded-lg bg-brand-green/5 border border-brand-green/20 px-3 py-2 text-slate-600">\n      Atual: <b class="text-slate-800">{{ artilheiro.player }}</b> · congelado em <b>{{ artilheiro.tier_points_at_edit }} pts</b>\n      {% if artilheiro.points %}· ganhou <b class="text-brand-green">{{ artilheiro.points }} pts</b>{% endif %}\n    </p>\n    {% endif %}\n    <form method="post" action="/apostas/artilheiro" class="flex flex-col gap-3">\n      <select name="player" class="border border-slate-300 rounded-lg py-2 px-3 outline-none focus:border-brand-green" required>\n        <option value="" disabled {{ \'selected\' if not artilheiro }}>Escolha um jogador…</option>\n        {% for p in players %}\n        <option value="{{ p }}" {{ \'selected\' if artilheiro and artilheiro.player == p }}>{{ p }}</option>\n        {% endfor %}\n      </select>\n      <button class="px-4 py-2 rounded-lg bg-brand-green text-white font-medium hover:brightness-110 transition">\n        Salvar · congela em {{ current_tier }} pts\n      </button>\n      <p class="text-xs text-slate-400">Trocar agora recalcula o valor para a faixa atual.</p>\n    </form>\n  </section>\n\n  <!-- Progresso do Brasil -->\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-1">Até onde o Brasil vai? <span class="text-brand-yellow">★</span></h2>\n    <p class="text-sm text-slate-500 mb-3">\n      Acerto exato vale 30 pts. Se ninguém cravar, quem chegar mais perto leva.\n      {% if not progress_open %}<span class="text-red-500 font-medium">Aposta encerrada.</span>{% endif %}\n    </p>\n    {% if brazil_progress %}\n    <p class="text-sm mb-3 rounded-lg bg-brand-green/5 border border-brand-green/20 px-3 py-2 text-slate-600">\n      Atual: <b class="text-slate-800">{{ phases_progress_labels[brazil_progress.phase_choice] }}</b>\n      {% if brazil_progress.points %}· ganhou <b class="text-brand-green">{{ brazil_progress.points }} pts</b>{% endif %}\n    </p>\n    {% endif %}\n    <form method="post" action="/apostas/brasil-progresso" class="flex flex-col gap-3">\n      <select name="phase_choice" class="border border-slate-300 rounded-lg py-2 px-3 outline-none focus:border-brand-green" {{ \'disabled\' if not progress_open }} required>\n        <option value="" disabled {{ \'selected\' if not brazil_progress }}>Escolha a fase…</option>\n        {% for ph in phases_progress %}\n        <option value="{{ ph }}" {{ \'selected\' if brazil_progress and brazil_progress.phase_choice == ph }}>\n          {{ phases_progress_labels[ph] }}\n        </option>\n        {% endfor %}\n      </select>\n      {% if progress_open %}\n      <button class="px-4 py-2 rounded-lg bg-brand-green text-white font-medium hover:brightness-110 transition">Salvar</button>\n      {% endif %}\n    </form>\n  </section>\n\n</div>\n{% endif %}\n{% endblock %}\n',
    'ranking.html': '{% extends "base.html" %}\n{% block title %}Ranking · Bolão da Copa 2026{% endblock %}\n{% block content %}\n<h1 class="text-xl font-semibold text-slate-900 tracking-tight mb-6">Ranking</h1>\n\n{% if user and my_row %}\n<div class="mb-4 rounded-xl border border-brand-green/20 bg-brand-green/5 p-4">\n  <p class="text-sm font-semibold text-slate-700 mb-3">\n    Você está em <span class="text-brand-green">#{{ my_pos }}</span> lugar com <span class="text-brand-green">{{ my_row.total }} pts</span>\n  </p>\n  <div class="grid grid-cols-2 md:grid-cols-4 gap-2 text-xs text-slate-500">\n    <div class="rounded-lg bg-white border border-slate-200 p-2.5 text-center">\n      <p class="font-semibold text-slate-900 text-lg tabular-nums">{{ my_row.pts_jogos }}</p>\n      <p>Jogos</p>\n    </div>\n    <div class="rounded-lg bg-white border border-slate-200 p-2.5 text-center">\n      <p class="font-semibold text-slate-900 text-lg tabular-nums">{{ my_row.pts_artilheiro }}</p>\n      <p>Artilheiro</p>\n    </div>\n    <div class="rounded-lg bg-white border border-slate-200 p-2.5 text-center">\n      <p class="font-semibold text-slate-900 text-lg tabular-nums">{{ my_row.pts_brasil_jogo }}</p>\n      <p>Neymar/Endrick</p>\n    </div>\n    <div class="rounded-lg bg-white border border-slate-200 p-2.5 text-center">\n      <p class="font-semibold text-slate-900 text-lg tabular-nums">{{ my_row.pts_progresso }}</p>\n      <p>Até onde Brasil</p>\n    </div>\n  </div>\n</div>\n{% endif %}\n\n{% if not ranking %}\n  <div class="rounded-xl bg-white border border-slate-200 p-8 text-center text-slate-400">Ninguém pontuou ainda.</div>\n{% else %}\n<div class="bg-white rounded-xl border border-slate-200 overflow-hidden">\n  <table class="w-full text-sm">\n    <thead>\n      <tr class="text-slate-400 text-xs uppercase tracking-wider border-b border-slate-200">\n        <th class="px-4 py-3 text-left w-12 font-medium">#</th>\n        <th class="px-4 py-3 text-left font-medium">Participante</th>\n        <th class="hidden md:table-cell px-4 py-3 text-right font-medium">Jogos</th>\n        <th class="hidden md:table-cell px-4 py-3 text-right font-medium">Art.</th>\n        <th class="hidden md:table-cell px-4 py-3 text-right font-medium">N/E</th>\n        <th class="hidden md:table-cell px-4 py-3 text-right font-medium">Brasil</th>\n        <th class="px-4 py-3 text-right font-medium">Total</th>\n      </tr>\n    </thead>\n    <tbody>\n      {% for row in ranking %}\n      <tr class="border-b border-slate-100 last:border-0 {{ \'bg-brand-green/5\' if user and row.user.id == user.id }}">\n        <td class="px-4 py-3 font-semibold text-slate-400">\n          {% if row.pos == 1 %}🥇{% elif row.pos == 2 %}🥈{% elif row.pos == 3 %}🥉{% else %}{{ row.pos }}{% endif %}\n        </td>\n        <td class="px-4 py-3">\n          <div class="flex items-center gap-2.5">\n            {% if row.user.picture_url %}\n            <img src="{{ row.user.picture_url }}" alt="" class="w-7 h-7 rounded-full ring-1 ring-slate-200" referrerpolicy="no-referrer">\n            {% else %}\n            <span class="w-7 h-7 rounded-full bg-slate-100 inline-flex items-center justify-center text-slate-400 text-xs">{{ (row.user.name or row.user.email)[0]|upper }}</span>\n            {% endif %}\n            <span class="text-slate-700">{{ row.user.name or row.user.email }}</span>\n          </div>\n        </td>\n        <td class="hidden md:table-cell px-4 py-3 text-right text-slate-500 tabular-nums">{{ row.pts_jogos }}</td>\n        <td class="hidden md:table-cell px-4 py-3 text-right text-slate-500 tabular-nums">{{ row.pts_artilheiro }}</td>\n        <td class="hidden md:table-cell px-4 py-3 text-right text-slate-500 tabular-nums">{{ row.pts_brasil_jogo }}</td>\n        <td class="hidden md:table-cell px-4 py-3 text-right text-slate-500 tabular-nums">{{ row.pts_progresso }}</td>\n        <td class="px-4 py-3 text-right font-semibold text-slate-900 tabular-nums">{{ row.total }}</td>\n      </tr>\n      {% endfor %}\n    </tbody>\n  </table>\n</div>\n{% endif %}\n{% endblock %}\n',
    'regras.html': '{% extends "base.html" %}\n{% block title %}Regras · Bolão da Copa 2026{% endblock %}\n{% block content %}\n<h1 class="text-xl font-semibold text-slate-900 tracking-tight mb-6">Regras e pontuação</h1>\n\n<div class="space-y-4">\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Palpites dos jogos</h2>\n    <ul class="text-sm space-y-1 list-disc list-inside text-slate-600">\n      <li>O bolão começa na <b>3ª rodada da fase de grupos</b>.</li>\n      <li>Você palpita o <b>placar</b> de cada jogo, editável até o <b>apito inicial</b>.</li>\n      <li>Jogos do <b>mata-mata</b> abrem quando os times do confronto são definidos.</li>\n      <li>A <b>disputa de 3º lugar</b> conta como jogo normal do mata-mata.</li>\n    </ul>\n    <table class="mt-3 text-sm w-full max-w-sm text-slate-600">\n      <tr class="border-b border-slate-100"><td class="py-1.5">Placar cravado</td><td class="text-right font-semibold text-slate-900">10 pts</td></tr>\n      <tr class="border-b border-slate-100"><td class="py-1.5">Acertou o vencedor/empate <b>e</b> o saldo de gols</td><td class="text-right font-semibold text-slate-900">7 pts</td></tr>\n      <tr class="border-b border-slate-100"><td class="py-1.5">Acertou só o vencedor/empate</td><td class="text-right font-semibold text-slate-900">5 pts</td></tr>\n      <tr><td class="py-1.5">Errou</td><td class="text-right font-semibold text-slate-400">0 pts</td></tr>\n    </table>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Artilheiro da Copa</h2>\n    <p class="text-sm text-slate-600 mb-2">\n      Escolha o artilheiro e troque quando quiser — a pontuação fica\n      <b>congelada conforme a fase do seu último palpite</b>. Se dois ou mais\n      jogadores empatarem na artilharia, acertar qualquer um deles vale a\n      pontuação cheia. Quanto mais cedo, mais vale:\n    </p>\n    <table class="text-sm w-full max-w-sm text-slate-600">\n      {% for stage, pts in artilheiro_tiers.items() %}\n      <tr class="border-b border-slate-100 last:border-0"><td class="py-1.5">{{ stage_labels[stage] }}</td><td class="text-right font-semibold text-slate-900">{{ pts }} pts</td></tr>\n      {% endfor %}\n    </table>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Palpites do Brasil <span class="text-brand-yellow">★</span></h2>\n    <ul class="text-sm space-y-1 list-disc list-inside text-slate-600">\n      <li>Em cada jogo do Brasil: <b>Neymar entra?</b> e <b>Endrick entra?</b> — 3 pts cada.</li>\n      <li><b>Até onde o Brasil vai?</b> Acerto exato vale 30 pts. Se ninguém cravar, quem chegar\n          mais perto leva. Editável até o início do bolão.</li>\n    </ul>\n  </section>\n</div>\n{% endblock %}\n',
    'admin.html': '{% extends "base.html" %}\n{% block title %}Admin · Bolão da Copa 2026{% endblock %}\n{% block content %}\n<h1 class="text-xl font-semibold text-slate-900 tracking-tight mb-6">Administração</h1>\n\n<div class="grid md:grid-cols-2 gap-4 mb-8">\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Importar jogos</h2>\n    <p class="text-sm text-slate-500 mb-3">Carrega a tabela de <code class="text-slate-600">data/fixtures.json</code> (só se ainda não houver jogos).</p>\n    <form method="post" action="/admin/seed">\n      <button class="px-4 py-2 rounded-lg bg-brand-green text-white font-medium hover:brightness-110 transition">Importar tabela</button>\n    </form>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Importar jogos faltando</h2>\n    <p class="text-sm text-slate-500 mb-3">Adiciona ao banco os jogos de <code class="text-slate-600">fixtures.json</code> que ainda não existem (seguro de rodar várias vezes).</p>\n    <form method="post" action="/admin/seed-missing">\n      <button class="px-4 py-2 rounded-lg bg-slate-700 text-white font-medium hover:brightness-110 transition">Importar faltando</button>\n    </form>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Sincronizar fixtures</h2>\n    <p class="text-sm text-slate-500 mb-3">Adiciona jogos reais e remove placeholders "A definir" das fases que já têm confrontos definidos em <code class="text-slate-600">fixtures.json</code>.</p>\n    <form method="post" action="/admin/sync-fixtures">\n      <button class="px-4 py-2 rounded-lg bg-amber-600 text-white font-medium hover:brightness-110 transition">Sincronizar fixtures</button>\n    </form>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Sincronizar da API</h2>\n    <p class="text-sm text-slate-500 mb-3">Preenche os confrontos do mata-mata já definidos e busca os placares finalizados na football-data.org, recalculando os pontos automaticamente. Requer <code class="text-slate-600">FOOTBALL_DATA_TOKEN</code>.</p>\n    <form method="post" action="/admin/sync-resultados">\n      <button class="px-4 py-2 rounded-lg bg-brand-blue text-white font-medium hover:brightness-110 transition">Sincronizar da API</button>\n    </form>\n  </section>\n\n  <section class="bg-white rounded-xl border border-slate-200 p-5">\n    <h2 class="font-semibold text-slate-900 mb-2">Gabaritos finais</h2>\n    <form method="post" action="/admin/gabarito" class="flex flex-col gap-3 text-sm text-slate-600">\n      <label>Artilheiro da Copa\n        <input name="top_scorer" value="{{ settlement.top_scorer if settlement else \'\' }}"\n               class="border border-slate-300 rounded-md py-1.5 px-2 w-full mt-1 outline-none focus:border-brand-green" placeholder="Nome do artilheiro (empate? separe por vírgula)">\n      </label>\n      <label>Até onde o Brasil foi\n        <select name="brazil_final_phase" class="border border-slate-300 rounded-md py-1.5 px-2 w-full mt-1 outline-none focus:border-brand-green">\n          <option value="">—</option>\n          {% for ph in phases_progress %}\n          <option value="{{ ph }}" {{ \'selected\' if settlement and settlement.brazil_final_phase == ph }}>\n            {{ phases_progress_labels[ph] }}\n          </option>\n          {% endfor %}\n        </select>\n      </label>\n      <button class="px-4 py-2 rounded-lg bg-brand-blue text-white font-medium hover:brightness-110 transition">Salvar e recalcular</button>\n    </form>\n  </section>\n</div>\n\n<h2 class="text-xs font-semibold uppercase tracking-wider text-slate-400 mb-2.5">Jogos ({{ matches|length }})</h2>\n<div class="space-y-2.5">\n  {% for m in matches %}\n  <article class="bg-white rounded-xl border border-slate-200 p-4">\n    <div class="flex items-center justify-between text-xs text-slate-400 mb-2">\n      <span>{{ stage_labels[m.stage] }} · {{ m.kickoff_at | dt_br }}</span>\n      <span>{% if m.finished %}encerrado{% elif m.teams_decided %}aberto{% else %}a definir{% endif %}</span>\n    </div>\n\n    <form method="post" action="/admin/match/{{ m.id }}/teams" class="flex flex-wrap items-center gap-2 text-sm mb-2">\n      <input name="home_team" value="{{ m.home_team }}" class="border border-slate-300 rounded-md py-1.5 px-2 w-40 outline-none focus:border-brand-green">\n      <span class="text-slate-300">vs</span>\n      <input name="away_team" value="{{ m.away_team }}" class="border border-slate-300 rounded-md py-1.5 px-2 w-40 outline-none focus:border-brand-green">\n      <label class="flex items-center gap-1 text-xs text-slate-500">\n        <input type="checkbox" name="teams_decided" {{ \'checked\' if m.teams_decided }}> times definidos\n      </label>\n      <button class="px-3 py-1.5 rounded-md bg-slate-700 text-white text-xs hover:bg-slate-800 transition">Salvar times</button>\n    </form>\n\n    <form method="post" action="/admin/match/{{ m.id }}/resultado" class="flex flex-wrap items-center gap-2 text-sm">\n      <span class="text-xs text-slate-400">Resultado:</span>\n      <input type="number" name="home_score" min="0" value="{{ m.home_score if m.home_score is not none else \'\' }}" class="border border-slate-300 rounded-md py-1.5 w-14 text-center outline-none focus:border-brand-green">\n      <span class="text-slate-300">:</span>\n      <input type="number" name="away_score" min="0" value="{{ m.away_score if m.away_score is not none else \'\' }}" class="border border-slate-300 rounded-md py-1.5 w-14 text-center outline-none focus:border-brand-green">\n      {% if m.is_brazil %}\n      <label class="flex items-center gap-1 text-xs text-slate-500"><input type="checkbox" name="neymar_played" {{ \'checked\' if m.neymar_played }}> Neymar entrou</label>\n      <label class="flex items-center gap-1 text-xs text-slate-500"><input type="checkbox" name="endrick_played" {{ \'checked\' if m.endrick_played }}> Endrick entrou</label>\n      {% endif %}\n      {% if m.stage != \'grupos\' %}\n      <div class="flex items-center gap-3 text-sm">\n        <span class="text-xs text-slate-400">{{ \'Quem ficou com o 3º:\' if m.stage == \'terceiro\' else \'Quem avançou:\' }}</span>\n        <label class="flex items-center gap-1 text-xs text-slate-500">\n          <input type="radio" name="who_advanced" value="home" {{ \'checked\' if m.who_advanced == \'home\' }}> {{ m.home_team }}\n        </label>\n        <label class="flex items-center gap-1 text-xs text-slate-500">\n          <input type="radio" name="who_advanced" value="away" {{ \'checked\' if m.who_advanced == \'away\' }}> {{ m.away_team }}\n        </label>\n      </div>\n      {% endif %}\n      <button class="px-3 py-1.5 rounded-md bg-brand-green text-white text-xs font-medium hover:brightness-110 transition">Lançar resultado</button>\n    </form>\n  </article>\n  {% endfor %}\n</div>\n{% endblock %}\n',
}
